import type { CueModalId } from '../core/ports';
import { useCue } from './useCue';

export type CueAnchorState = {
  closeTour: () => void;
  goBack: () => void;
  goNext: () => void;
  isActive: boolean;
  isFirstStep: boolean;
  isLastStep: boolean;
};

const inactiveAnchorState: CueAnchorState = {
  closeTour: () => undefined,
  goBack: () => undefined,
  goNext: () => undefined,
  isActive: false,
  isFirstStep: false,
  isLastStep: false,
};

export const useCueAnchor = ({
  modalId,
  stepKey,
}: {
  modalId: CueModalId;
  stepKey: string;
}): CueAnchorState => {
  const cue = useCue();

  if (cue.mode !== 'tour' || cue.modalId !== modalId) {
    return inactiveAnchorState;
  }

  const isActive = cue.eligible && cue.currentStepKey === stepKey;

  return {
    closeTour: cue.closeTour,
    goBack: cue.goBack,
    goNext: cue.goNext,
    isActive,
    isFirstStep: cue.stepIndex === 0,
    isLastStep: cue.stepIndex >= cue.totalSteps - 1,
  };
};
